#include <stdio.h>

int factorial(int n) {
    if (n == 0)
        return 1;
    else
        return n * factorial(n - 1);
}

int main() {
    printf("Factorial of 5: %d\n", factorial(5));
    return 0;
}

#include <stdio.h>

void swap(int x, int y) {
    int temp = x;
    x = y;
    y = temp;
    printf("Inside function: x=%d, y=%d\n", x, y);
}

int main() {
    int a = 10, b = 20;
    swap(a, b);
    printf("Inside main: a=%d, b=%d\n", a, b);
    return 0;
}

